
import { describe, it, expect } from 'vitest';
import { createEntanglementMatrix, distributeEntropyByMass } from '../void-entanglement';
import { createObserver } from '../void-game-engine';

describe('void-entanglement', () => {
  it('distributes entropy by topological mass shielding bosons', () => {
    const matrix = createEntanglementMatrix(['did:1', 'did:2']);
    
    const fermion = { ...createObserver('did:1', 1, 'mystic', 'scientist', 'fermion'), energy: 100 };
    const boson = { ...createObserver('did:2', 2, 'builder', 'aesthete', 'boson'), energy: 100 };
    
    // Fermion has 5x multiplier
    const results = distributeEntropyByMass(matrix, [fermion, boson], 600);
    
    const fermionHit = results.find(r => r.did === 'did:1')?.absorbedEntropy ?? 0;
    const bosonHit = results.find(r => r.did === 'did:2')?.absorbedEntropy ?? 0;
    
    // Fermion should take significantly more
    expect(fermionHit).toBeGreaterThan(bosonHit * 3);
  });
});
